/// `paths` から指定キーの非空値を取り出す。欠落/空文字なら `default` を返す。
/// キーが無い/空のときは厳密に既定挙動を維持する。
fn path_or<'a>(paths: &'a HashMap<String, String>, key: &str, default: &'a str) -> &'a str {
    paths
        .get(key)
        .map(String::as_str)
        .filter(|s| !s.is_empty())
        .unwrap_or(default)
}

/// 1ポーリングセッションで使い回す状態。
#[derive(Debug, Clone)]
pub struct Session {
    /// INNERTUBE_API_KEY。
    pub api_key: String,
    /// WEB クライアントのバージョン。
